#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long D; scanf("%lld", &D);
        if(D==0){
            printf("1\n1\n");
            continue;
        }
        const int MAX_CHUNK = 99998;
        int *arr = (int*)malloc(sizeof(int)*30000); // enough for all cases
        int idx=0;
        while(D>0){
            int c = (int)(D>MAX_CHUNK?MAX_CHUNK:D);
            int y = c+1; // ≤ 99999
            int x = y+1; // ≤ 100000
            arr[idx++] = x;
            arr[idx++] = y;
            arr[idx++] = 1;
            D -= c;
        }
        printf("%d\n", idx);
        for(int i=0;i<idx;i++){
            if(i) printf(" ");
            printf("%d", arr[i]);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

