const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
const MAX_CHUNK = 99998;
let output = [];
for (let t = 0; t < T; ++t) {
  let D = BigInt(input[idx++]);
  if (D === 0n) {
    output.push('1');
    output.push('1');
    continue;
  }
  let ans = [];
  while (D > 0n) {
    const c = Number(D > BigInt(MAX_CHUNK) ? BigInt(MAX_CHUNK) : D);
    const y = c + 1; // <= 99999
    const x = y + 1; // <= 100000
    ans.push(x, y, 1);
    D -= BigInt(c);
  }
  output.push(String(ans.length));
  output.push(ans.join(' '));
}
